from prometheus_client import start_http_server, Gauge

# Define Prometheus gauges for database credentials
db_username = Gauge('database_username', 'Database username')
db_password = Gauge('database_password', 'Database password')
db_host = Gauge('database_host', 'Database host')
db_connection_string = Gauge('database_connection_string', 'Database connection string')

def export_db_credentials():
    # Example database credentials (replace with actual values)
    credentials = {
        'username': 'admin',
        'password': 'securepassword123',
        'host': 'localhost',
        'connection_string': 'dbname=test user=admin password=securepassword123 host=localhost'
    }

    # Set the gauge metrics
    db_username.set_to_current_time()
    db_password.set_to_current_time()
    db_host.set_to_current_time()
    db_connection_string.set_to_current_time()

    # Set metric labels
    db_username.labels(username=credentials['username'])
    db_password.labels(password=credentials['password'])
    db_host.labels(host=credentials['host'])
